  <!-- Top Bar -->
  <div class="border border-slate-200 p-6 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
    <div>
      <h1 class="text-xl font-black text-slate-900 tracking-tight uppercase">Gestión de Alumnos</h1>
      <p class="text-slate-500 text-xs mt-1">Control de alumnos inscritos, estado de cuentas y niveles de suscripción.</p>
